 1→import type { AssertionContext, AssertionResult } from "@dec-bench/eval-core";
 2→
 3→async function queryRows<T>(ctx: AssertionContext, sql: string): Promise<T[]> {
 4→  const result = await ctx.clickhouse.query({ query: sql, format: "JSONEachRow" });
 5→  return (await (result as any).json()) as T[];
 6→}
 7→
 8→export async function daily_total_matches_source(ctx: AssertionContext): Promise<AssertionResult> {
 9→  const sourceRows = await queryRows<{ n: number }>(ctx, "SELECT count() AS n FROM analytics.raw_events");
10→  const rollupRows = await queryRows<{ s: number }>(ctx, "SELECT sum(event_count) AS s FROM analytics.rollup_daily");
11→  const sourceCount = Number(sourceRows[0]?.n ?? 0);
12→  const rollupCount = Number(rollupRows[0]?.s ?? 0);
13→  const passed = sourceCount === rollupCount;
14→  return {
15→    passed,
16→    message: passed ? "Daily total matches source." : `Source ${sourceCount}, rollup ${rollupCount}.`,
17→    details: { sourceCount, rollupCount },
18→  };
19→}
