clickhouse-client --multiquery <<'EOF'
-- Fix daily rollup: truncate and repopulate with actual counts
TRUNCATE TABLE analytics.rollup_daily;
INSERT INTO analytics.rollup_daily
SELECT toDate(event_ts) AS day, count() AS event_count
FROM analytics.raw_events
GROUP BY day;

-- Populate hourly rollup
TRUNCATE TABLE analytics.rollup_hourly;
INSERT INTO analytics.rollup_hourly
SELECT toStartOfHour(event_ts) AS hour, count() AS event_count
FROM analytics.raw_events
GROUP BY hour;

-- Populate monthly rollup
TRUNCATE TABLE analytics.rollup_monthly;
INSERT INTO analytics.rollup_monthly
SELECT toStartOfMonth(event_ts) AS month, count() AS event_count
FROM analytics.raw_events
GROUP BY month;
EOF

clickhouse-client --multiquery <<'EOF'
SELECT 'HOURLY:' AS label;
SELECT * FROM analytics.rollup_hourly ORDER BY hour;
SELECT 'DAILY:' AS label;
SELECT * FROM analytics.rollup_daily ORDER BY day;
SELECT 'MONTHLY:' AS label;
SELECT * FROM analytics.rollup_monthly ORDER BY month;
SELECT 'SOURCE TOTAL:' AS label;
SELECT count() AS n FROM analytics.raw_events;
SELECT 'DAILY TOTAL:' AS label;
SELECT sum(event_count) AS s FROM analytics.rollup_daily;
SELECT 'HOURLY TOTAL:' AS label;
SELECT sum(event_count) AS s FROM analytics.rollup_hourly;
SELECT 'MONTHLY TOTAL:' AS label;
SELECT sum(event_count) AS s FROM analytics.rollup_monthly;
EOF

